head.script:
//м „м—ӯліҖмҲҳ
scwin.memJson = $c.data.getMemInfo();

scwin.valueObject = null;

scwin.strToDay = $c.date.getServerDateTime("yyyyMMdd");
scwin.strFromDate = scwin.strToDay.substring(0,6) + "01";
scwin.strLastDate = $c.date.getLastDateOfMonth(scwin.strToDay.substring(0,6));
scwin.strToDate = scwin.strFromDate.substring(0,6) + scwin.strLastDate;

scwin.userHomeClsCd   = scwin.memJson.userHomeClsCd;        // мӮ¬мҡ©мһҗмҶҢмҶҚкө¬л¶„мҪ”л“ң  
scwin.vCoCd           = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // мҶҢмҶҚ мһҗнҡҢмӮ¬  
scwin.vCoClsCd        = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; //нҡҢкі„_нҡҢмӮ¬кө¬л¶„('CO035' : 0:лҸҷл¶Җ EXPRESS)
scwin.vUserHomeClsCd  = scwin.memJson.userHomeClsCd;        // мӮ¬мҡ©мһҗмҶҢмҶҚкө¬л¶„мҪ”л“ң   
scwin.vAcctDeptCd     = scwin.memJson.acctDeptCd;
scwin.vAcctDeptNm     = scwin.memJson.acctDeptNm;
scwin.vUserId         = scwin.memJson.userId;
scwin.vUserNm         = scwin.memJson.userNm;
scwin.vPerVehclNo     = "";
scwin.vPerVehclNm     = "";
scwin.vDeptCost       = "";
scwin.hid_costClsCd   = "";

scwin.onpageload = function() {
	scwin.valueObject    = $c.data.getParameter();
    const codeOptions = [
        { grpCd: "ZZ604", compID: "gr_master:fuelKndCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    const codeOptions2 = [
        {
            method: "getLuxeComboData",
            param1: "PerVehclMgntEBC",
            param2: "retrievePerVehclAccount",
            param3: ["03"],
            compID: "acb_acctCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions2);
};

//-------------------------------------------------------------------------
// UDC лЎңл”© мҷ„лЈҢ нӣ„
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function() {
    // нҢқм—…мңјлЎң м—ҙлҰ° кІҪмҡ° мһҗмӮ°лІҲнҳё м„ёнҢ…
    if (typeof(scwin.valueObject) != "undefined" && scwin.valueObject != null) {
        let parent_slipNo = scwin.valueObject.slipNo;
        if (parent_slipNo != null) {
            dma_search.set("slipNo", parent_slipNo);
            $c.gus.cf_HideObject([buttonArea]);
            $c.gus.cf_HideObject([searchArea]);
            let e = await $c.sbm.execute(sbm_search);
            scwin.sbm_search_submitdone(e);
            $c.gus.cfDisableObjects([btn_Search]);
            return;
        } 
    }

    ed_runDtFrom.setValue(scwin.strFromDate);
    ed_runDtTo.setValue(scwin.strToDay);
    ed_slipDt.setValue(scwin.strToDay);

    ed_userId.setValue(scwin.vUserId);
    ed_userNm.setValue(scwin.vUserNm);
    acb_acctCd.setSelectedIndex(0);
    ed_acctDeptCd.setValue(scwin.vAcctDeptCd);
    ed_acctDeptNm.setValue(scwin.vAcctDeptNm);

    if (scwin.vAcctDeptCd != "00009") { //мһ¬кІҪнҢҖмқҖ м „мІҙ мЎ°нҡҢк°ҖлҠҘ
        $c.gus.cfDisableObjects([ed_userId, ed_userNm]);
        $c.gus.cfEnableObj(btn_userId, false);
    } else {
        $c.gus.cfEnableObjects([ed_userId, ed_userNm]);
        $c.gus.cfEnableObj(btn_userId, true);
    }

    $c.gus.cfDisableObjects([btn_Modify, btn_AddRow, btn_UndoRow, btn_CopyRow, btn_Pro, btn_Save, btn_Delete]);
    scwin.f_SeachVehclNo();
    scwin.f_SeachDeptCost();
};

//-------------------------------------------------------------------------
// лЎңк·ёмқё мӮ¬мҡ©мһҗ к°ңмқём°Ёлҹү л“ұлЎқмІҙнҒ¬
//-------------------------------------------------------------------------
scwin.f_SeachVehclNo = async function() {
    // SELECT м Ҳ
    let param1 = "VEHCL_NO   as COL1 "  //м°ЁлҹүлІҲнҳё
            + ",VEHCL_NM     as COL2 "  //м°ЁлҹүлӘ…
            + ",''           as COL3 "
            + ",''           as COL4 "
            + ",''           as COL5 "
            + ",''           as COL6 "
            + ",''           as COL7 "
            + ",''           as COL8 "
            + ",''           as COL9 "
            + ",''           as COL10 "
            ;

    // лҢҖмғҒн…Ңмқҙлё”
    let param2 = "TB_ZZ614";
    let param3 = "AND USE_YN = 1 AND APPRV_YN = 1 AND USER_ID = '" + scwin.vUserId + "'";
    let param4 = "VEHCL_NO";

    dma_perVehcl.set("param1", param1);
    dma_perVehcl.set("param2", param2);
    dma_perVehcl.set("param3", param3);
    dma_perVehcl.set("param4", param4);

    sbm_perVehcl.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
																						+ "&param2=" + param2 
																						+ "&param3=" + param3
																						+ "&param4=" + param4
																						;
    let e = await $c.sbm.execute(sbm_perVehcl);
    scwin.sbm_perVehcl_submitdone(e);
};

//-------------------------------------------------------------------------
// лЎңк·ёмқё мӮ¬мҡ©мһҗл¶Җм„ң  л№„мҡ©кө¬л¶„ нҷ•мқё
//-------------------------------------------------------------------------
scwin.f_SeachDeptCost = function() {
    // SELECT м Ҳ
    let param1 = "COST_CLS_CD  as COL1 " //л№„мҡ©кө¬л¶„
            + ",''           as COL2 "
            + ",''           as COL3 "
            + ",''           as COL4 "
            + ",''           as COL5 "
            + ",''           as COL6 "
            + ",''           as COL7 "
            + ",''           as COL8 "
            + ",''           as COL9 "
            + ",''           as COL10 "
            ;

    // лҢҖмғҒн…Ңмқҙлё”
    let param2 = "TB_CO001";
    let param3 = "AND ACCT_DEPT_CD = '" + scwin.vAcctDeptCd + "'";
    let param4 = "COST_CLS_CD";

    dma_deptCost.set("param1", param1);
    dma_deptCost.set("param2", param2);
    dma_deptCost.set("param3", param3);
    dma_deptCost.set("param4", param4);

    sbm_deptCost.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
																						+ "&param2=" + param2 
																						+ "&param3=" + param3
																						+ "&param4=" + param4
																						;
    $c.sbm.execute(sbm_deptCost);
};

//-------------------------------------------------------------------------
// мЎ°нҡҢ
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ed_runDtFrom, ed_runDtTo]);
    if (!ret) {
        return true;
    }

    if (ed_runDtFrom.getValue() == "" || ed_runDtTo.getValue() == "") {
        await $c.win.alert("мҡҙн–үмқјмӢңлҠ” н•„мҲҳ мһ…л Ҙ н•ӯлӘ©мһ…лӢҲлӢӨ.");
        return;
    }

    //л¶Җм„ң
    if (scwin.vAcctDeptCd != "00009") {
        if(ed_userId.getValue() == "") {
            await $c.win.alert("мӮ¬мҡ©мһҗлҠ” н•„мҲҳ мһ…л Ҙ н•ӯлӘ©мһ…лӢҲлӢӨ.");
            ed_userId.focus();
            return;
        }  
    }

    if (!$c.gus.cfIsAfterDate(ed_runDtFrom.getValue().trim(), ed_runDtTo.getValue().trim())) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_039));
        ed_runDtFrom.focus();
        return false;
    }
    let e = await $c.sbm.execute(sbm_search);
    scwin.sbm_search_submitdone(e);
};

//-------------------------------------------------------------------------
// м ҖмһҘмӢң
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    //  н•„мҲҳмһ…л ҘмӮ¬н•ӯ нҷ•мқё
    let ret = await $c.gus.cfValidate([gr_master]);
    if (!ret) {
        return;
    }

    if (ds_master.getModifiedIndex().length === 0) {
        await $c.win.alert("ліҖкІҪлҗң мӮ¬н•ӯмқҙ м—ҶмҠөлӢҲлӢӨ.");
        return;
    }

    // м ҖмһҘм „ мӣҗк°Җ/нҢҗкҙҖл¶Җм„ңм—җ л”°лҘё кі„м •мІҙнҒ¬
    for (let i = 0; i < ds_master.getRowCount() ; i++) {
        let acctCd = ds_master.getCellData(i, "acctCd");
        let costClsCd = ds_master.getCellData(i, "costClsCd");

        /* 01 мӣҗк°Җ , 02 нҢҗкҙҖл№„, 03 мӣҗк°Җ+нҢҗкҙҖл№„ */
        if (acctCd.substring(0,1) == "4" && costClsCd == "02") { //мӣҗк°Җ
            await $c.win.alert("нҢҗкҙҖл№„л¶Җм„ңм—җ мӣҗк°Җкі„м • м„ нғқмқҖ л¶Ҳк°Җн•©лӢҲлӢӨ.");
            return;
        } else if (acctCd.substring(0,1) == "5" && costClsCd == "01") { //нҢҗкҙҖл№„
            await $c.win.alert("мӣҗк°Җл¶Җм„ңм—җ нҢҗкҙҖл№„кі„м • м„ нғқмқҖ л¶Ҳк°Җн•©лӢҲлӢӨ.");
            return;
        }
    }

    if (await $c.win.confirm("м ҖмһҘн•ҳмӢңкІ мҠөлӢҲк№Ң?") == true) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// мӮӯм ңмӢң
//-------------------------------------------------------------------------
scwin.f_Delete = async function() {
    if (ds_master.getModifiedIndex().length === 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "лҚ°мқҙнғҖ"));
        return;
    }

    let msg = "лІҲм§ё лҚ°мқҙнғҖлҠ” м „н‘ңлӮҙм—ӯмқҙ мһҲм–ҙ мӮӯм ңн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.";
    // мқҙлҜё л°ңн–үлҗңкұҙ мӮӯм ңн•ҳм§Җ м•ҠлҠ”лӢӨ.
    for (let i = 0; i < ds_master.getRowCount() ; i++) {
        if (ds_master.getRowStatus(i) == "U" && ds_master.getCellData(i, "slipNo") != "") {
            await $c.win.alert((i + 1) + msg);
            return;
        }
    }

    if (await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, "м„ нғқн•ҳмӢ  лҚ°мқҙнғҖ")) == true) {
        for (let i = ds_master.getRowCount() - 1; i >= 0 ; i--) {
            if (ds_master.getCellData(i, "chk") == "T") {
                ds_master.deleteRow(i);
            }
        }

        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// м „н‘ңл°ңн–үмӢң
//-------------------------------------------------------------------------
scwin.f_Process = async function() {
    if (ds_master.getModifiedIndex().length === 0) {
        await $c.win.alert("ліҖкІҪлҗң мӮ¬н•ӯмқҙ м—ҶмҠөлӢҲлӢӨ.");
        return;
    }

    //  н•„мҲҳмһ…л ҘмӮ¬н•ӯ нҷ•мқё
    let ret = await $c.gus.cfValidate([gr_master]);
    if (!ret) {
        return;
    }

    if (ed_slipDt.getValue() == "") {
        await $c.win.alert("мһ‘м„ұмқјмһҗлҠ” н•„мҲҳ мһ…л Ҙ н•ӯлӘ©мһ…лӢҲлӢӨ.");
        return;
    }

    if (ed_summary.getValue() == "") {
        await $c.win.alert("м Ғмҡ”лҠ” н•„мҲҳ мһ…л Ҙ н•ӯлӘ©мһ…лӢҲлӢӨ.");
        return;
    }

    if (await $c.win.confirm("м „н‘ң л°ңн–үн•ҳмӢңкІ мҠөлӢҲк№Ң?") == true) {
        await scwin.f_SlipCreate();
    }
};

//-------------------------------------------------------------------------
// м „н‘ңлӮҙм—ӯ мғқм„ұ
//-------------------------------------------------------------------------
scwin.f_SlipCreate = async function() {debugger;
    ds_slip.removeAll();
    ds_slip.insertRow();

    let chkCnt                  = 0;
    let _acctDeptCd             = "";   //к·ҖмҶҚл¶Җм„ң
    let _adjmClntNontNo         = "";   //м •мӮ°мІҳ
    let _acctCd                 = "";   //кі„м •
    let _crn                    = "";   //мӮ¬м—…мһҗлІҲнҳё
    let _supAmt                 = 0;    //м§ҖмӣҗкёҲм•Ў
    let _etcAmt                 = 0;    //кё°нғҖл№„мҡ©
    let _runYm                  = "";   //мҡҙн–үл…„мӣ”
    let _vatDeclarAcctDeptCd    = "";   //л¶Җк°Җм„ёмӢ кі л¶Җм„ң
    let _userId                 = "";   //л¶Җк°Җм„ёмӢ кі л¶Җм„ң

    //м„ нғқн•ң лӮҙм—ӯмқҙ лҸҷмқјн•ң кұҙмқём§Җ нҷ•мқё
    let chkRunYm        = true;
    let chkAcctDeptCd   = true;
    let chkAdjmClntNo   = true;
    let chkAcctCd       = true;

    for (let i = 0; i < ds_master.getRowCount() ; i++) {
        if (ds_master.getCellData(i, "chk") == "T") {
            chkCnt ++;

            if (ds_master.getRowStatus(i)  == "C") {
                await $c.win.alert("м ҖмһҘнӣ„ м „н‘ңл°ңн–ү к°ҖлҠҘн•©лӢҲлӢӨ.");
                return;
            }

            if (chkCnt > 1) { //2кұҙ мқҙмғҒ м„ нғқ мӢң к·ҖмҶҚл¶Җм„ң, кұ°лһҳмІҳ, м Ғмҡ” лҸҷмқјн•ң лӮҙмҡ©мқём§Җ нҷ•мқё

                if (_runYm != ds_master.getCellData(i, "runDt").substring(0,6)) {
                    chkRunYm = false;
                }
                if (_acctDeptCd != ds_master.getCellData(i, "acctDeptCd")) {
                    chkAcctDeptCd = false;
                }
                if (_adjmClntNo != ds_master.getCellData(i, "adjmClntNo")) {
                    chkAdjmClntNo = false;
                }
                if (_acctCd != ds_master.getCellData(i, "acctCd")) {
                    chkAcctCd = false;
                }
            }

            _supAmt = parseInt(_supAmt) + parseInt(ds_master.getCellData(i, "supAmt"));
            _acctDeptCd = ds_master.getCellData(i, "acctDeptCd");
            _adjmClntNo = ds_master.getCellData(i, "adjmClntNo");
            _acctCd     = ds_master.getCellData(i, "acctCd");
            _crn        = ds_master.getCellData(i, "crn");
            _etcAmt     = parseInt(_etcAmt) + parseInt(ds_master.getCellData(i, "etcAmt"));
            _userId     = ds_master.getCellData(i, "userId");
            _runYm      = ds_master.getCellData(i, "runDt").substring(0,6);
        }
    }

    if (chkCnt == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_007, "м „н‘ңл°ңн–үн•  лӮҙм—ӯ"));  // @мқ„(лҘј) м„ нғқн•ҳмӢӯмӢңмҳӨ.
        return;
    }

    if (_adjmClntNo == "") {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмқҳ м •мӮ°мІҳк°Җ мЎҙмһ¬н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.");
        return;
    } else if (!chkAdjmClntNo) {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмӨ‘ м •мӮ°мІҳк°Җ лӢӨлҘёкұҙмқҙ мЎҙмһ¬н•©лӢҲлӢӨ.");
        return;
    }

    if (_acctDeptCd == "") {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмқҳ к·ҖмҶҚл¶Җм„ңк°Җ мЎҙмһ¬н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.");
        return;
    } else if (!chkAcctDeptCd) {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмӨ‘ к·ҖмҶҚл¶Җм„ңк°Җ лӢӨлҘёкұҙмқҙ мЎҙмһ¬н•©лӢҲлӢӨ.");
        return;
    }

    if (_acctCd == "") {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмқҳ кі„м •мҪ”л“ңк°Җ мЎҙмһ¬н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.");
        return;
    } else if (!chkAcctCd) {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмӨ‘ кі„м •мҪ”л“ңк°Җ лӢӨлҘёкұҙмқҙ мЎҙмһ¬н•©лӢҲлӢӨ.");
        return;
    }

    _vatDeclarAcctDeptCd = await scwin.f_VatDeclarAcctDeptCd(_acctDeptCd);

    if (_supAmt == 0) {
        await $c.win.alert("м„ нғқн•ң лӮҙм—ӯмқҳ м§ҖмӣҗкёҲм•Ўмқҙ 0мӣҗмһ…лӢҲлӢӨ. м „н‘ңл°ңн–ү л¶Ҳк°Җн•©лӢҲлӢӨ.");
        return;
    }

    ds_slip.setCellData(0, "slipDt", ed_slipDt.getValue());
    ds_slip.setCellData(0, "summary", ed_summary.getValue());
    ds_slip.setCellData(0, "crn", _crn);
    ds_slip.setCellData(0, "acctDeptCd", _acctDeptCd);
    ds_slip.setCellData(0, "vatAcctDeptCd", _vatDeclarAcctDeptCd);
    ds_slip.setCellData(0, "adjmClntNo", _adjmClntNo);

    ds_slip.setCellData(0, "slipKndCd", "A27");       // м „н‘ңмў…лҘҳ-к°ңмқём°Ёлҹүм •мӮ°
    ds_slip.setCellData(0, "adjmClsCd", "1");         // м •мӮ°кө¬л¶„-лҜём§Җкёүл№„мҡ©  
    ds_slip.setCellData(0, "outbrAcctCd", "2100820"); // лҜём§Җкёүл№„мҡ©-мӮ¬мӣҗкұ°лһҳмІҳ
    ds_slip.setCellData(0, "evidClsCd", "99");        // мҰқл№ҷмў…лҘҳ - кё°нғҖ

    ds_slip.setCellData(0, "coClsCd", scwin.vCoClsCd); 
    ds_slip.setCellData(0, "coCd", scwin.vCoCd);
    ds_slip.setCellData(0, "acctCd", _acctCd);
    ds_slip.setCellData(0, "supAmt", _supAmt);
    ds_slip.setCellData(0, "etcAmt", _etcAmt);

    if (!(_acctCd == "4203610" || _acctCd == "5002110")) { //м°Ёлҹүмң м§Җл№„-мң лҘҳл№„ кі„м •мқҖ мӮ¬мӣҗлІҲнҳё кҙҖлҰ¬м•Ҳн•Ё
        ds_slip.setCellData(0, "userId", _userId); 
    }

    if (_etcAmt > 0) {
        if (_acctCd == "4203610") { //мһ…л Ҙ кі„м •кіјлӘ©мқҙ м°Ёлҹүмң м§Җл№„-мң лҘҳл№„мқё кІҪмҡ°
            ds_slip.setCellData(0, "etcAcctCd", "4203660"); //мӣҗ)м°Ёлҹүмң м§Җл№„-кё°нғҖ
        } else if (_acctCd == "5002110") {
            ds_slip.setCellData(0, "etcAcctCd", "5002160"); //нҢҗ)м°Ёлҹүмң м§Җл№„-кё°нғҖ
        } else {
            ds_slip.setCellData(0, "etcAcctCd", _acctCd);
        }
    }
    $c.sbm.execute(sbm_process);
};

//-------------------------------------------------------------------------
// л¶Җк°Җм„ёмӢ кі л¶Җм„ңмҪ”л“ң мЎ°нҡҢ
//-------------------------------------------------------------------------
scwin.f_VatDeclarAcctDeptCd = async function(_acctDeptCd) { 
    let param = "," + _acctDeptCd + "," + scwin.vCoCd + "," + scwin.vCoClsCd + "," + ed_slipDt.getValue().substring(0,4);
    let check = "T";
    let popTemp = "ZZ";
    let vatDeclarAcctDeptCd = "";

