// м—‘м…Җ Download
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
    if (ds_master.getRowCount() == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_002));
        return;
    }

    let colCount = 0;
    for(let i = 0; i < gr_master.getTotalCol(); i++) {
        if(gr_master.getColumnVisible(i) == true) {
            colCount++;
        }
    }

    let infoArr = [{
        rowIndex : 0, 
        colIndex : 0, 
        rowSpan : 1,
        colSpan : colCount, 
        text : "к°ңмқём°Ёлҹүмң лҘҳл№„м •мӮ° лӮҙм—ӯ", 
        textAlign : "center",
        fontSize : 18,
        drawBorder:false,
        color : "black",
        backgroundColor : "white"
    }];

    const options = {
        fileName: 'м •мӮ°мІҳлҰ¬ лӮҙм—ӯ.xlsx',
        sheetName: 'м •мӮ°мІҳлҰ¬ лӮҙм—ӯ',
        startRowIndex : 2,
        startColumnIndex : 0,
        columnMove:true,
        columnMoveWithFooter:true,
        type : 1
    };
    gr_master.setFooterStyle("column44", "text-align", "right");
    $c.data.downloadGridViewExcel(gr_master, options, infoArr);
    gr_master.setFooterStyle("column44", "text-align", "center");
};

