scwin.f_AddRow = function() {
    let newRow = ds_master.insertRow();
    gr_master.setFocusedCell(newRow, "runDt");
    ds_master.setCellData(newRow, "userId", scwin.vUserId); //ліёмқём°Ёлҹүм—җ лҢҖн•ҳм„ңл§Ң л“ұлЎқ к°ҖлҠҘ
