scwin.f_CopyRow = function() {
    let rowIdx = gr_master.getFocusedRowIndex();
    let newRow = ds_master.insertRow();

    for(let j = 0; j < ds_master.getColumnCount(); j++){
        ds_master.setCellData(newRow, ds_master.getColumnID(j), ds_master.getCellData(rowIdx, ds_master.getColumnID(j)));
    }
    ds_master.setCellData(rowIdx+1, "slipNo", "");
};

