scwin.f_openPopUp = async function(orgObjCd, orgObjNm, select_code, sFlag) {
    let param = '';
    let code = "";
    let name = "";

    if (sFlag != "SKIP") {
        code = orgObjCd.getValue();
        name = orgObjNm.getValue();
    } else {
        code = orgObjCd;
        name = orgObjNm;
    }

    switch (select_code) {
        case '1': //мӮ¬мҡ©мһҗ
            param = scwin.vCoCd + "," + scwin.vCoClsCd; 
            await udc_userId.cfCommonPopUp(scwin.udc_userId_callBackFunc, code, name, "T", null, null, null, null, param, null, null, null, null, null, "F", null, null);  
            break;
        case '2': //м°ЁлҹүлІҲнҳё
            param = ed_userId.getValue(); 
            await udc_vehclNo.cfCommonPopUp(scwin.udc_vehclNo_callBackFunc, code, name, "T", null, null, null, null, param, null, null, null, null, null, "F", null, null);
            break;
        case '3': //к·ҖмҶҚл¶Җм„ң
            param = ed_runDtFrom.getValue().trim() + ",," + scwin.vCoCd + "," + scwin.vCoClsCd;
            await udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc, code, name, "T", null, null, null, null, param, null, null, null, null, null, "F", null, null);
            break;
        case '4': //м •мӮ°мІҳ
            param = ",,," + scwin.vCoCd;
            await udc_adjmClntNo.cfCommonPopUp(scwin.udc_adjmClntNo_callBackFunc, code, name, "T", null, null, null, null, param, null, null, null, null, null, "F", null, null);  
            break;
    }
};

