//-------------------------------------------------------------------------
// PopUpм°Ҫм—җм„ң мӮ¬мҡ©лҗҳлҠ” к°Ғ Cd,Nmм—җ лҢҖн•ҙм„ң POPUPн‘ңмӢң л°Ҹ н•ҙлӢ№ к°’мқҙ м—Ҷмқ„кІҪмҡ°лҠ” мҪ”л“ңмҷҖ мқҙлҰ„мқ„ мҙҲкё°нҷ” мӢңнӮЁлӢӨ.
// flagк°’мқҙ CD:мҪ”л“ңліҖкІҪмқҙ м—Ҷмңјл©ҙ POPUPм•Ҳлӣ°мӣҖ, NM:л¬ҙмЎ°кұҙ POPUPлӣ°мӣҖ
scwin.f_CheckPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    if (!orgObjCd.options) orgObjCd.options = {};
    if (!orgObjNm.options) orgObjNm.options = {};

    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            await scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        } else {
            orgObjNm.options.hidVal = "";
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
        orgObjNm.options.hidVal = "";
    }
};

//-------------------------------------------------------------------------
// нҢқм—…кІ°кіј
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function(orgObjCd, orgObjNm, rtnList) {
    if (!orgObjCd.options) orgObjCd.options = {};
    if (!orgObjNm.options) orgObjNm.options = {};

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        orgObjCd.setValue(rtnList[0]);   // мҪ”л“ңк°’
        orgObjNm.setValue(rtnList[1]);   // мҪ”л“ңлӘ…
        orgObjCd.options.hidVal = rtnList[0]; // HIDDEN мҪ”л“ңк°’
        orgObjNm.options.hidVal = rtnList[1]; // HIDDEN мҪ”л“ңлӘ…
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.options.hidVal = "";
        orgObjNm.options.hidVal = "";
    }
};

scwin.f_openCommPopUpGrid = async function(disGubun, row, pCode, pName, pClose, pAllSearch) {
    let pWhere = "";
    scwin.tempGridRow = row;

    switch (disGubun) {
        case 1: //м„ұлӘ…
            pWhere = scwin.vCoCd + "," + scwin.vCoClsCd;
            udc_comPopupGird.setSelectId("retrieveAcEmpInfo");

            await udc_comPopupGird.cfCommonPopUp(scwin.udc_acEmpInfoGrid_callBackFunc, pCode, pName, pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, "мӮ¬мӣҗмЎ°нҡҢ,мӮ¬мӣҗмҪ”л“ң,мӮ¬мӣҗлӘ…", null, null);
            break;

        case 2: //м°Ёмў…
            if (ds_master.getCellData(row, "runDt") == "") {
                await $c.win.alert("мҡҙн–үмқјмӢңлҘј лЁјм Җ мһ…л Ҙн•ҙ мЈјм„ёмҡ”.");
                ds_master.setCellData(row, "vehclNm", "");
                ds_master.setCellData(row, "vehclNo", "");
                return;
            }   
            if (ds_master.getCellData(row, "userNm") == "") {
                await $c.win.alert("мӮ¬мҡ©мһҗкІҖмғүл¶Җн„°н•ҳм„ёмҡ”.");
                ds_master.setCellData(row, "vehclNm", "");
                ds_master.setCellData(row, "vehclNo", "");
                return;
            }

            pWhere = ds_master.getCellData(row, "userId") + "," + ds_master.getCellData(row, "runDt"); //ліёмқём°Ёлҹүл§Ң мЎ°нҡҢ
            udc_comPopupGird.setSelectId("retrievePersonVehclInfo");

            await udc_comPopupGird.cfCommonPopUp(scwin.udc_personVehclInfoGrid_callBackFunc, pCode, pName, pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, "к°ңмқём°ЁлҹүмЎ°нҡҢ,м°ЁлҹүлІҲнҳёмҪ”л“ң,м°ЁлҹүлӘ…", null, null);
            break;

        case 3: //к·ҖмҶҚл¶Җм„ң
            pWhere = ds_master.getCellData(row, "runDt") + ",," + scwin.vCoCd + "," + scwin.vCoClsCd;
            udc_comPopupGird.setSelectId("retrieveAcctDeptCdInfo3");

            await udc_comPopupGird.cfCommonPopUp(scwin.udc_acctDeptCdInfo3Grid_callBackFunc, pCode, pName, pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, "л¶Җм„ңмЎ°нҡҢ,к·ҖмҶҚл¶Җм„ңмҪ”л“ң,к·ҖмҶҚл¶Җм„ңлӘ…", null, null);
            break;

        case 4: //м •мӮ°мІҳ
            pWhere = ",,," + scwin.vCoCd;
            udc_comPopupGird.setSelectId("retrieveClntList");

            await udc_comPopupGird.cfCommonPopUp(scwin.udc_clntListGrid_callBackFunc, pCode, pName, pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, "кұ°лһҳмІҳмЎ°нҡҢ,кұ°лһҳмІҳмҪ”л“ң,кұ°лһҳмІҳлӘ…", null, null);  
            break;

        case 5: //кі„м •кіјлӘ©
            pWhere = "FI633," + ds_master.getCellData(row, "costClsCd");
            udc_comPopupGird.setSelectId("retrieveBudgetAcctCd");

            await udc_comPopupGird.cfCommonPopUp(scwin.udc_budgetAcctCdGrid_callBackFunc, pCode, pName, pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, "кі„м •мЎ°нҡҢ,кі„м •мҪ”л“ң,кі„м •лӘ…", null, null);
            break;
    }
};

